import{_ as i,o as n,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung057.jpg",g=JSON.parse('{"title":"Übung Lektion 34","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung34.md","filePath":"lektionen/uebung34.md"}'),a={name:"lektionen/uebung34.md"};function s(o,e,u,m,d,b){return n(),l("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-34" tabindex="-1">Übung Lektion 34 <a class="header-anchor" href="#ubung-lektion-34" aria-label="Permalink to &quot;Übung Lektion 34&quot;">​</a></h1><p>Bilden Sie zu folgenden Verbformen die in Person, Zahl und Genus entprechenden Perfektformen:</p><ol><li>रक्षिष्यन्ति । ररक्षुर्</li><li>स्रक्ष्यति । ससर्ज</li><li>सिञ्चते । सिषिचे</li><li>वर्तते । ववृते</li><li>प्रवेक्ष्यति । प्रविविशुर्</li><li>भनक्ति । बभञ्ज</li><li>लुभ्यन्ति । लुलुभुर्</li><li>रुन्धते । रुरुधिरे</li><li>रोदिति । रुरोद</li><li>बध्नाति । बबन्ध</li><li>युध्यन्ते । युयुधिरे</li><li>युङ्क्ते । युयुजे</li><li>मुह्यन्ति । मुमुहुर्</li><li>मुञ्चते । मुमुचे</li><li>जीवन्ति । जिजीवुर्</li><li>भोक्ष्यते । बुभुजे</li><li>आप्नुवन्ति । आपुर्</li><li>भिन्त्ते । बिभिदे</li><li>भोत्स्यन्ते । बुबुधिरे</li><li>नर्तिष्यति । ननर्त</li><li>अश्नाति । आश</li><li>द्वेष्टि । दिवेष</li><li>पश्यन्ति । ददृशुर्</li><li>दुग्धे । दुदुहे</li><li>सन्ति । आसुर्</li><li>आदेक्ष्यन्ति । आदिदिशुर्</li><li>छिनत्ति । चिछेद</li><li>क्रुध्यति । चुक्रोध</li><li>अस्यति । आस</li><li>कुप्यन्ति । चुकुपुर्</li><li>इच्छन्ति । ईषुर्</li></ol><p>Übersetzen Sie folgenden Text aus dem पद्मपुराण über Gaben an Brahmanen:</p><blockquote><p>क्षितिं सशस्यां यो दद्याद्ब्राह्मणाय द्विजोत्तम ।<br> विष्णुलोके सुखं भुङ्क्ते यावदिन्द्राश्चतुर्दश ॥१॥<br> सप्तद्वीपां महीं दत्त्वा यत्पुण्यं प्राप्यते द्विज ।<br> तत्पुण्यं प्राप्नुयान्मर्त्यो धेनुं यच्छन्द्विजातये ॥२॥<br> तिलप्रमाणं स्वर्णं यो ब्राह्मणाय प्रयच्छति ।<br> हरिनिकेतनं याति युक्तं कोटिकुलैरपि ॥३॥<br> सालङ्कारां द्विजश्रेष्ठ कन्यां यच्छति यो नरः ।<br> स गच्छेद्ब्रह्मसदनं पुनर्जन्म न विद्यते ॥४॥<br> अन्नं वारि द्विजश्रेष्ठ येन दत्तम् महीतले ।<br> तेन दत्तानि दानानि सर्वाणि च द्विजर्षभ ॥५॥</p></blockquote><p>Bester der Zweimalgeborenen! Wer einem Brahmanen die Erde samt ihren Feldfrüchten schenkt, genießt die Welt Viṣṇus so lange wie vierzehn Indras. Zweimalgeborener! Das Verdienst, das jemand erhält, der die ganze Welt mit ihren sieben Kontinenten verschenkt, das erhält ein Sterblicher, der einem Brahmanen eine Kuh gibt. Wer einem Brahmanen Gold so klein wie ein Sesamkorn gibt, der kommt in die Wohnstadt Haris (Viṣṇus) zusammen mit 10 Millionen Familien. Bester der Zweimalgeborenen! Ein Mann, der ein Mädchen samt Schmuck (einem Brahmanen) gibt, der kommt zum Sitz Brahmās und hat keine Wiedergeburt mehr.  Bester der Zweimalgeborenen! Wer Speise und Wasser auf der Erdoberfläche gegeben hat, der hat alle Gaben gegeben, Stier unter den Zweimalgeborenen!</p><p>Erklärungen:</p><p>Vokativ sg. der Maskulina / Neutra auf -a lautet auf -a: z.B. देव &quot;Gott!&quot;</p><p>चतुर्दश vierzehn</p><p>सप्त sieben</p><p>जन्म Nom./Akk. sg. zu जन्मन् n. Geburt</p><p>सर्व 3 &quot;alle, ganz&quot; (dekliniert nach Pronominaldeklination)</p><p><img src="'+t+'" alt=""><br> Abb.: तिलप्रमाणम्<br><em>Sesamum indicum</em> L.<br> [Bildquelle: Soebe / Wikipedia. GNU FDLicense]</p>',14)])])}const h=i(a,[["render",s]]);export{g as __pageData,h as default};
